INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'ffef998a-1bd7-564e-8936-489dd313fc40'::uuid, 'Бард. Коллегия Доблести'::text, 'Воспевайте подвиги древних героев
Барды Коллегии Доблести — отважные рассказчики, чьи истории хранят память о великих героях прошлого. Эти барды воспевают великие деяния в сводчатых залах или собравшимся вокруг костра слушателям. Они путешествуют, чтобы стать свидетелями великих событий из первых уст и гарантировать, что память об этих событиях не исчезнет.
Своими песнями они вдохновляют новые поколения достичь тех же высот, что и герои прошлого.'::text, 'BARD_COLLEGE_OF_VALOR_PHB'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_VALOR_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '64923e74-f0c7-5394-87bc-f5b47d8be609'::uuid, 'Бард. Коллегия Знания'::text, 'Погрузитесь в глубины магических знаний.
Барды Коллегии Знаний собирают заклинания и секреты из разных источников, таких как научные тома, мистические обряды и крестьянские сказки.
Члены коллегии собираются в библиотеках и университетах, чтобы поделиться своими знаниями друг с другом. Они также встречаются на фестивалях или государственных мероприятиях, где могут выявить коррупцию, разоблачить ложь и высмеять самодовольных деятелей власти.'::text, 'BARD_COLLEGE_OF_LORE_PHB'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_LORE_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '57e42419-629c-5f86-bd1c-1aa0afcf58e1'::uuid, 'Бард. Коллегия Очарования'::text, 'Сплетайте очаровательную магию фей
Коллегия Очарования берёт своё начало в завораживающей магии Страны фей. Барды, изучающие эту магию, вплетают нити красоты и ужаса в свои песни и истории, и самые могущественные из них могут облачаться в потустороннее величие. Выступления таких бардов вызывают тоскливые мысли о забытой невинности, пробуждают бессознательные воспоминания о давних страхах и затрагивают нити эмоций даже самых чёрствых слушателей.'::text, 'BARD_COLLEGE_OF_GLAMOUR_PHB'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_GLAMOUR_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'e049be57-2151-5e06-8078-5f40d8f69571'::uuid, 'Бард. Коллегия Танца'::text, 'Двигайтесь в гармонии с космосом
Барды Коллегии Танца знают, что слова творения не могут быть заключены в речь или песню; слова произносятся движениями небесных тел и текут через движения мельчайших существ. Эти барды практикуют способ пребывания в гармонии с кружащимся космосом, который подчёркивает ловкость, скорость и грацию.'::text, 'BARD_COLLEGE_OF_DANCE_PHB'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_DANCE_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '7641fd95-5da8-5016-a282-61154a1eb01c'::uuid, 'Бард. Коллегия Луны'::text, 'Вдохновляйте союзников древними сказаниями
Коллегия луны ведёт своё происхождение от древних друидических кругов островов Муншае, которые поручили первым бардам этой коллегии сохранять истории островов и их народов. Эти барды черпают силу из волшебства фей и древней энергии лунных колодцев, чтобы поддерживать союзников, защищать природу и творить свои произведения.'::text, 'BARD_COLLEGE_OF_THE_MOON_FRHOF'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_THE_MOON_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '884b8fd2-c966-5a6a-92bd-eb13c95fed73'::uuid, 'Бард. Коллегия Духов'::text, 'Призывайте духов с той стороны
Используя оккультные атрибуты, барды из Коллегии духов призывают легендарных и давно умерших духов, чтобы вновь изменить мир. Однако такие сущности капризны, и то, что бард вызывает, не всегда полностью поддаётся его контролю.'::text, 'BARD_COLLEGE_OF_SPIRITS_UAHS'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_SPIRITS_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '3f131290-98d8-57b1-99f8-3ddb6c43d07e'::uuid, 'Бард. Коллегия Луны'::text, 'Вдохновляйте союзников первобытными историями
Коллегия луны берёт своё начало в древних кругах друидов островов Муншае, которые поручили первым бардам этой коллегии запечатлеть истории островов и их жителей. Эти барды черпают силы из фейской магии островов и первозданной мощи лунных источников, чтобы укреплять своих союзников, защищать природный мир и вдохновлять свои бардовские произведения. Такие произведения обычно основаны на известных мифах Муншае — о причудах шаловливых фей, свирепости зверя и загадках лунных источников.'::text, 'BARD_COLLEGE_OF_THE_MOON_UAFRS'::text, 'e768eed6-ad5e-4a4f-b48b-bf99f74373a9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARD_COLLEGE_OF_THE_MOON_UAFRS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'd391f3bf-66ae-5aa4-9b08-43d6381293c3'::uuid, 'Варвар. Путь Берсерка'::text, 'Направьте ярость в неистовый гнев
Варвары, ступившие на Путь Берсерка, направляют свою ярость в основном на насилие. Их путь — это необузданная ярость. Они получают удовольствие от хаоса битвы, позволяя своей ярости захватить и усилить их.'::text, 'BARBARIAN_PATH_OF_THE_BERSERKER_PHB'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARBARIAN_PATH_OF_THE_BERSERKER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '6799787f-db37-53a6-8c5e-d09eaad47c9a'::uuid, 'Варвар. Путь Дикого сердца'::text, 'Живите в гармонии с животным миром
Варвары, ступившие на Путь Дикого сердца, считают себя родственными животным. Эти варвары изучают магические способы общения с животными, и их ярость усиливает их связь с животными, поскольку наполняет варваров этого пути сверхъестественной силой.'::text, 'BARBARIAN_PATH_OF_THE_WILD_HEART_PHB'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARBARIAN_PATH_OF_THE_WILD_HEART_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b3d7c2f8-4171-5168-b670-20066af53f33'::uuid, 'Варвар. Путь Мирового древа'::text, 'Проследите корни и ветви Мультивселенной
Варвары, ступившие на Путь Мирового древа, соединяются с космическим деревом Иггдрасиль через свою ярость. Это дерево растёт среди Внешних планов, соединяя их друг с другом и Материальным планом. Эти варвары черпают магию дерева для жизненной силы и как средство для перемещения между планами.'::text, 'BARBARIAN_PATH_OF_THE_WORLD_TREE_PHB'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARBARIAN_PATH_OF_THE_WORLD_TREE_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '98cd3033-3167-5f6b-aeff-96d0b47494ac'::uuid, 'Варвар. Путь Фанатика'::text, 'Неистовствуйте в восторженном союзе с богом
Варвары, ступившие на Путь Фанатика, получают благословения от бога или пантеона богов. Эти варвары переживают свою ярость, как восторженный эпизод божественного единения, который наполняет их силой. Они часто являются союзниками жрецов и других последователей своего бога или пантеона.'::text, 'BARBARIAN_PATH_OF_THE_ZEALOT_PHB'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'BARBARIAN_PATH_OF_THE_ZEALOT_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'de1b677d-089d-5ea7-903f-2257d3daf5d7'::uuid, 'Варвар. Путь буревестника'::text, 'Овладевайте яростью шторма.
Варвары, следующие пути буревестника, учатся превращать свою ярость в покров первобытной магии, который кружится вокруг них, словно буря. Во время Ярости такие варвары черпают силу из стихийных сил природы, создавая мощные магические эффекты.'::text, 'PATH_OF_THE_STORM_HERALD_UASU'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PATH_OF_THE_STORM_HERALD_UASU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '86124164-1dd0-5bbc-b30b-ab91c93b3b73'::uuid, 'Варвар. Путь духовного стража'::text, 'Призывайте духов на помощь в сражении.
Варвары, идущие по пути духовного стража, взывают к духам — будь то звериные духи природы, духи предков или духи первородной стихийной силы, — чтобы те направляли и защищали их. Когда такие варвары впадают в ярость, они вступают в контакт с царством духов и просят их о помощи.'::text, 'PATH_OF_THE_SPIRITUAL_GUARDIAN_UASU'::text, 'b5c59b67-4405-4342-b351-09a264e38adf'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PATH_OF_THE_SPIRITUAL_GUARDIAN_UASU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '985f318a-3ad9-5955-8790-7679c9e3272f'::uuid, 'Воин. Мастер боевых искусств'::text, 'Мастер сложных боевых приёмов
Мастера боевых искусств — это ученики искусства битвы, изучающие боевые приёмы, передаваемые из поколения в поколение. Самые опытные мастера битвы — это разносторонние личности, которые сочетают свои тщательно отточенные боевые навыки с академическим обучением в области истории, теории и искусств.'::text, 'FIGHTER_BATTLE_MASTER_PHB'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_BATTLE_MASTER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'c1027484-e5fa-5d53-bb13-bc144f669889'::uuid, 'Воин. Мистический рыцарь'::text, 'Поддерживайте боевые навыки с помощью магии.
Мистические рыцари сочетают в себе боевое мастерство, присущее всем бойцам, с тщательным изучением магии. Их заклинания дополняют и расширяют их боевые навыки, обеспечивая дополнительную защиту для укрепления их доспехов, а также позволяя им одновременно сражаться со множеством врагов с помощью взрывной магии.'::text, 'FIGHTER_ELDRITCH_KNIGHT_PHB'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_ELDRITCH_KNIGHT_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '495e739c-8ab9-553d-9ccb-279534d40f00'::uuid, 'Пси-воин'::text, 'Усильте физическую мощь псионическими силами.
Пси-воины пробуждают силу своего разума, чтобы увеличить свою физическую мощь. Они используют эту псионическую силу, наполняя своё оружие энергией, атакуя телекинетической энергией и создавая барьеры ментальной силы.'::text, 'FIGHTER_PSI_WARRIOR_PHB'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_PSI_WARRIOR_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '7fdacb8e-c7a7-58ba-82f9-cffde2945a46'::uuid, 'Воин. Чемпион'::text, 'Мастер сложных боевых приёмов
Мастера боевых искусств — это ученики искусства битвы, изучающие боевые приёмы, передаваемые из поколения в поколение. Самые опытные мастера битвы — это разносторонние личности, которые сочетают свои тщательно отточенные боевые навыки с академическим обучением в области истории, теории и искусств.'::text, 'FIGHTER_CHAMPION_PHB'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_CHAMPION_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '73b0769e-2430-52e2-b6ad-6241bff47145'::uuid, 'Воин. Знаменосец'::text, 'Вдохновляйте героев силой лидерства.
Знаменосцы — образцы доблести и лидерства, которые защищают невинных и воодушевляют других приключенцев на служение справедливости и свободе.
Многие из них — рыцари, служащие в Кормире, Серебряных Маршах, Дамаре, Чессенте или других землях Фаэруна. Они странствуют по королевствам как странствующие рыцари, неся борьбу со злом за пределами родных границ. Знаменосец полагается на рассудительность, отвагу и верность рыцарскому кодексу, чтобы сокрушать зло. В одиночку он — искусный воин, но, возглавив группу союзников, способен превратить даже плохо вооружённое ополчение в яростный боевой отряд.'::text, 'FIGHTER_BANNERET_FRHOF'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_BANNERET_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b0fd04f8-8cb3-5515-aded-d33e68b244d3'::uuid, 'Воин. Арканный лучник'::text, 'Зачаровывайте магией боеприпасы
Арканный лучник изучает уникальный эльфийский метод стрельбы из лука, который вплетает магию в атаки, создавая сверхъестественные эффекты. Первые арканные лучники сторожили свои общины, зорко высматривая опасности и используя пропитанные магией стрелы, чтобы побеждать монстров и захватчиков. Со временем представители других видов освоили мистические эльфийские приёмы сочетания магии с искусством стрельбы и расширили их использование на самые разные дальнобойные типы оружия, применяя эти таланты в жизни приключенца.'::text, 'FIGHTER_ARCANE_ARCHER_UAAU'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_ARCANE_ARCHER_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '8a3242f2-8adb-51fc-b35e-5be2c70d784e'::uuid, 'Воин. Гладиатор'::text, 'Овладейте жестокостью и кровавым зрелищем.
Гладиаторы — это не только воины, но и артисты. Будь то драки в подпольных ристалищах или сражения за выживание на залитых кровью аренах, гладиатор сочетает боевое мастерство с театральностью, чтобы восхищать и устрашать зрителей.'::text, 'FIGHTER_GLADIATOR_UAAS'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_GLADIATOR_UAAS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'a650c50d-20e9-5754-a53d-565dc6b9a743'::uuid, 'Воин. Кавалерист'::text, 'Защищайте союзников пешим и верхом.
Кавалеристы преуспевают в бою верхом и охраняют своих подопечных, часто защищая старших или слабых. Кавалерист одинаково уверенно чувствует себя во главе кавалерийской атаки или в обмене остротами на званом ужине.'::text, 'CAVALIER_UASU'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CAVALIER_UASU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '40c3a52f-656f-5bcb-a652-4f13ebcd1753'::uuid, 'Воин. Рыцарь пурпурного дракона'::text, 'Возвещайте о величии аметистовых драконов
Рыцари пурпурного дракона — это образцы доблести и лидерства, которые сотрудничают с аметистовыми драконами. Такие рыцари стремятся защищать невинных и вдохновлять других приключенцев на служение справедливости и свободе. Хотя изначально Орден пурпурного дракона был основан в Кормире, новых рекрутов набирают из любых регионов, где процветает рыцарство, включая Серебряные пределы, Дамар и Чессенту.
Персонажи этого подкласса являются особенными в ордене. В отличие от большинства рыцарей пурпурного дракона, которые сотрудничают со взрослыми аметистовыми драконами, персонаж рыцарь пурпурного дракона формирует псионическую связь с детёнышем аметистового дракона. Эта связь необратимо меняет и дракона, и рыцаря, позволяя дракону набирать силу вместе со своим рыцарем-партнёром.'::text, 'FIGHTER_PURPLE_DRAGON_KNIGHT_UAFRS'::text, 'd37773f5-fc06-4c99-b048-e6cafd1ac8fa'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'FIGHTER_PURPLE_DRAGON_KNIGHT_UAFRS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'db4d02e7-0fda-5970-9bbe-bd0f25868043'::uuid, 'Волшебник. Воплотитель'::text, 'Творите взрывные эффекты стихий
Вы сосредоточили свои исследования на магии, которая создаёт могущественные стихийные эффекты (например, лютый холод, обжигающее пламя, раскатистый гром, трескучие молнии или едкая кислота). Некоторые воплотители находят своё призвание в армии, где служат в качестве артиллеристов, уничтожая вражеские войска издалека. Другие же используют свои силы, чтобы защищать остальных, а некоторых интересует лишь собственная выгода.'::text, 'WIZARD_EVOKER_PHB'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_EVOKER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '8759fec6-b27f-5c1e-a066-deabada07b7d'::uuid, 'Волшебник. Иллюзионист'::text, 'Плетите коварные обманные заклинания
Вы специализируетесь на магии, которая ослепляет чувства и одурачивает разум, а создаваемые вами иллюзии заставляют невозможное казаться реальным.'::text, 'WIZARD_ILLUSIONIST_PHB'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_ILLUSIONIST_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '7cac55c0-2821-53dd-8e84-d7fc60654cc0'::uuid, 'Волшебник. Оградитель'::text, 'Изгоняйте врагов и защищайте товарищей
Исследуя магию, вы сосредотачиваетесь на заклинаниях блокировки, изгнания или защиты — тех, что позволяют снять пагубный эффект, изгнать злую силу и защитить слабых. К оградителям обращаются, когда возникает необходимость в обряде экзорцизма над губительным духом, когда место нужно защитить от магического шпионажа или когда требуется закрыть портал на иной план. Приключенцы ценят оградителей за ту защиту, которую они могут предоставить от вражеской магии и других видов атак.'::text, 'WIZARD_ABJURER_PHB'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_ABJURER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '9b43bf98-b010-5358-97b9-df6e290559c8'::uuid, 'Волшебник. Прорицатель'::text, 'Раскройте тайны Мультивселенной
За советом к прорицателю обращаются те, кто жаждет яснее понять прошлое, настоящее и будущее. Являясь прорицателем, вы стремитесь снять покровы пространства, времени и сознания. Вы работаете над освоением заклинаний распознания, удалённого наблюдения, сверхъестественного знания и предвидения.'::text, 'WIZARD_DIVINER_PHB'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_DIVINER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '4c4ac43f-0711-5475-9a9b-a4c49318609f'::uuid, 'Волшебник. Песнь клинка'::text, 'Владейте мечом и магией в элегантном тандеме
Песнь клинка — это школа волшебства, сочетающая фехтование и танец. В бою певцы клинка используют серию сложных, изящных манёвров, которые отражают удары врага и позволяют направить магию в разрушительные атаки и изощрённую защиту. Многие, кто наблюдал за работой певца клинка, вспоминают это как одно из самых прекрасных впечатлений в своей жизни: великолепный танец, сопровождаемый звоном поющего клинка.
Искусство песни клинка тесно связано с древними эльфийскими обществами, которые первыми овладели этим мастерством и дали ему название. Даже сегодня большинство певцов клинка происходят из старых эльфийских королевств, таких как Кормантир, или из неэльфийских обществ, которые разделяют земли и историю с эльфами, таких как Серебряные пределы.
Откуда бы ни происходили эти мастера, они известны тем, что путешествуют по всем землям, помогая простым людям и совершая героические поступки. Немногие общины встречают прибытие певца клинка иначе, чем как добрый знак.'::text, 'WIZARD_BLADESINGER_FRHOF'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_BLADESINGER_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '49901958-85de-585e-9e37-f36d57d1a002'::uuid, 'Волшебник. Некромант'::text, 'Властвуйте над силами смерти и нежити
Вы исследуете космические силы жизни, смерти и нежити. Будучи некромантом, вы учитесь управлять энергией, которая оживляет всех существ. По мере роста вашего мастерства вы обучаетесь с помощью магии высасывать жизнь из существа, превращая его жизненную энергию в волшебную силу. Многие считают некромантов злобными или жуткими, хотя не все некроманты — злые. Тем не менее, манипулирование жизнью и смертью считается табу во многих обществах.'::text, 'NECROMANCER_UAAU'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'NECROMANCER_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '1760aed5-1f8b-518e-bfb4-9a37e7abdab5'::uuid, 'Волшебник. Очарователь'::text, 'Пленяйте и обольщайте других
Ваша магия туманит или пленяет умы. Одни очарователи используют свои умения, чтобы поощрять мир и смягчать жестокость, а другие — ради эгоистичных целей. Большинство занимает промежуточное положение.'::text, 'WIZARD_ENCHANTER_UAAU'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_ENCHANTER_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'd2645b76-8756-565f-bf53-22c6d1305f19'::uuid, 'Волшебник. Песнь клинка'::text, 'Владейте мечом и магией в элегантном тандеме
Песнь клинка — это школа волшебства, сочетающая фехтование и танец. В бою певцы клинка используют серию сложных, изящных манёвров, которые отражают удары врага и позволяют направить магию в разрушительные атаки и изощрённую защиту. Многие, кто наблюдал за работой певца клинка, вспоминают это как одно из самых прекрасных впечатлений в своей жизни: великолепный танец, сопровождаемый звоном поющего клинка.
Искусство песни клинка тесно связано с древними эльфийскими обществами, которые первыми овладели этим мастерством и дали ему название. Даже сегодня большинство певцов клинка происходят из старых эльфийских королевств, таких как Кормантир, или из неэльфийских обществ, которые разделяют земли и историю с эльфами, таких как Серебряные пределы.
Откуда бы ни происходили эти мастера, они известны тем, что путешествуют по всем землям, помогая простым людям и совершая героические поступки. Немногие общины встречают прибытие певца клинка иначе, чем как добрый знак.'::text, 'WIZARD_BLADESINGER_UAFRS'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_BLADESINGER_UAFRS'::text
