INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '656e0acb-369d-51d8-b3c8-d8fb17a30fe4'::uuid, 'Волшебник. Преобразователь'::text, 'Трансформируйте энергию и материю
Вы изучаете заклинания, изменяющие энергию и материю. Для вас мир — не неизменный объект, а крайне пластичная субстанция. Ваша магия даёт вам инструменты, чтобы стать кузнецом реальности.
Одни преобразователи — изобретатели-шутники, другие же с мрачной серьёзностью стремятся к божественной силе творить и разрушать миры.'::text, 'WIZARD_TRANSMUTER_UAAU'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_TRANSMUTER_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '01730100-5b9a-5756-b850-3aaf34e03181'::uuid, 'Волшебник. Призыватель'::text, 'Шагайте через пространство и вызывайте существ из пустоты
Вы считаете расстояние и материю лишь гибкими рекомендациями, а не незыблемыми законами. Призыватель черпает силу магии, позволяющей мгновенно перемещать существ| сквозь пространство и вызывать их, чтобы они сражались за вас.'::text, 'WIZARD_CONJURER_UAAU'::text, 'dadeba2d-0278-4577-87aa-81defe56dab9'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WIZARD_CONJURER_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b6359fb2-0ad4-5adf-a4b5-b486f20ae88a'::uuid, 'Друид. Круг звёзд'::text, 'Используйте секреты, скрытые в созвездиях
Круг звёзд отслеживает небесные узоры с незапамятных времён, открывая секреты, скрытые среди созвездий. Понимая эти секреты, друиды этого круга стремятся использовать силы космоса.'::text, 'DRUID_CIRCLE_OF_THE_STARS_PHB'::text, '9898735e-04b8-4fd7-96f1-0e7759f2bab4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'DRUID_CIRCLE_OF_THE_STARS_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '571177e6-3f14-5be4-a55e-597f56dc504e'::uuid, 'Друид. Круг земли'::text, 'Празднуйте связь с природным миром
Круг Земли состоит из мистиков и мудрецов, которые охраняют древние знания и обряды. Эти друиды встречаются в священных кругах деревьев или стоячих камней, чтобы шептать первобытные тайны на друидском языке. Самые мудрые члены круга председательствуют как главные священники своих общин.'::text, 'DRUID_CIRCLE_OF_THE_LAND_PHB'::text, '9898735e-04b8-4fd7-96f1-0e7759f2bab4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'DRUID_CIRCLE_OF_THE_LAND_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'd561d0ab-75e8-52fc-a33c-ba777767a9f0'::uuid, 'Друид. Круг луны'::text, 'Примите формы животных для охраны природы.
Друиды Круга Луны используют лунную магию, чтобы преобразовать себя. Этот орден собирается под луной, чтобы делиться новостями и проводить ритуалы.
Изменчивый, как луна, друид этого круга может бродить ночью как большая кошка, а на следующий день парить над верхушками деревьев как орёл, а затем проламывать подлесок как медведь, чтобы отогнать вторгшегося монстра. Дикая природа у друида в крови.'::text, 'DRUID_CIRCLE_OF_THE_MOON_PHB'::text, '9898735e-04b8-4fd7-96f1-0e7759f2bab4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'DRUID_CIRCLE_OF_THE_MOON_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'e05cd979-4c67-5983-9b0d-9c778cef44d5'::uuid, 'Друид. Круг моря'::text, 'Станьте единым с приливами и штормами
Друиды Круга моря черпают силы из бурных океанов и штормов. Некоторые считают себя воплощениями гнева природы, стремясь отомстить тем, кто опустошает природу. Другие ищут мистического единения с природой, настраивая себя на приливы и отливы, следуя за потоками течений и волн и слушая непостижимый шёпот и рёв ветров.'::text, 'DRUID_CIRCLE_OF_THE_SEA_PHB'::text, '9898735e-04b8-4fd7-96f1-0e7759f2bab4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'DRUID_CIRCLE_OF_THE_SEA_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'c0c0ea17-58f6-56cd-854f-f6b4a3863137'::uuid, 'Друид. Круг сохранения'::text, 'Оберегайте природу и исцеляйте мир.
Друиды из круга сохранения неустанно трудятся над тем, чтобы сберечь природные ресурсы и восстановить места, разрушенные жадностью и эксплуатацией. Сочетая охранную и восстанавливающую магию, друиды этого круга защищают жизнь и распространяют её по земле. Самые могущественные представители этого круга способны возвращать жизненную силу бесплодным землям, превращая пустоши в цветущую дикую местность.'::text, 'DRUID_CIRCLE_OF_PRESERVATION_UAAS'::text, '9898735e-04b8-4fd7-96f1-0e7759f2bab4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'DRUID_CIRCLE_OF_PRESERVATION_UAAS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '0f4c204e-63b7-5b97-baa8-3b58b4d8a2c8'::uuid, 'Жрец. Домен войны'::text, 'Вдохновляйте на доблесть и сокрушайте врагов
Война имеет множество проявлений. Она может сделать героев из обычных людей. Она может быть безрассудной и ужасной, с актами жестокости и трусости, затмевающими примеры доблести и храбрости.
Жрецы, которые присягают домену войны, преуспевают в сражении, вдохновляя других на доблую битву или превращая акты насилия в молитвы.
Боги Домена Войны наблюдают за воинами и вознаграждают их за их великие деяния. Среди них чемпионы чести и рыцарства, а также боги разрушения и грабежа. Некоторые боги войны занимают более нейтральную позицию, поощряя войну во всех её проявлениях и поддерживая воинов в любых обстоятельствах.'::text, 'CLERIC_WAR_DOMAIN_PHB'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_WAR_DOMAIN_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '2af2025b-bee3-5c03-848a-8b7dc28fa590'::uuid, 'Жрец. Домен жизни'::text, 'Успокойте раны мира Домен жизни фокусируется на положительной энергии, которая помогает поддерживать всю жизнь в Мультивселенной. Жрецы, присягающие этому домену, являются мастерами лечения, использующими жизненную силу для исцеления ран. Само существование зависит от положительной энергии, связанной с этим доменом, поэтому жрец практически любой религии может выбрать его. Этот домен особенно связан с божествами земледелия, богами исцеления или терпения, а также богами дома и общества. Религиозные ордена целителей также стремятся овладеть магией этого домена.'::text, 'CLERIC_LIFE_DOMAIN_PHB'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_LIFE_DOMAIN_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '275752b5-8673-5342-994b-6280ae6d2c10'::uuid, 'Жрец. Домен обмана'::text, 'Плетите хитрости и нарушайте порядок
Домен обмана предлагает магию обмана, иллюзии и скрытности. Жрецы, владеющие этой магией, являются разрушительной силой в мире, оскорбляя гордость, высмеивая тиранов, освобождая пленников и презирая пустые традиции. Они предпочитают уловки и розыгрыши прямой конфронтации.
Боги обмана — это озорники и подстрекатели, которые постоянно бросают вызов принятому порядку как среди богов, так и среди смертных. Они воплощают силы перемен и социальных потрясений. Они покровители воров, негодяев, шулеров, мятежников и освободителей. Религиозные ордены, действующие тайно, особенно те, которые стремятся подорвать деспотические правительства или иерархии, также используют силу домена обмана.'::text, 'CLERIC_TRICKERY_DOMAIN_PHB'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_TRICKERY_DOMAIN_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '2ba137c3-08f8-5c1c-b8be-0c3b4ed69460'::uuid, 'Жрец. Домен света'::text, 'Несите свет, чтобы изгнать тьму
Домен Света проявляет божественную силу, чтобы вызывать ослепляющий огонь и озарение. Жрецы, владеющие этой силой, являются просветлёнными душами, наполненными сиянием и силой проницательного взора своих божеств, призванные изгонять ложь и сжигать тьму. Домен Света связан с богами истины, бдительности, красоты, проницательности и обновления. Некоторые из этих богов отождествляются с солнцем или воспринимаются как возничие, направляющие солнце по небу. Другие являются стражами, которые обличают обман. Некоторые являются божествами красоты и артистизма, которые учат, что искусство является средством совершенствования души.'::text, 'CLERIC_LIGHT_DOMAIN_PHB'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_LIGHT_DOMAIN_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'dafaebe0-b0ae-57e9-893b-5211714b766d'::uuid, 'Жрец. Домен знаний'::text, 'Постигайте тайны и овладейте разумом.
Домен Знаний превозносит обучение и понимание превыше всего. Жрецы, черпающие силу из этого домена, изучают эзотерические знания, собирают древние фолианты, исследуют тайные места и анализируют процессы разума. Для них знание ценнее материальных богатств, а обучение — это форма поклонения. Библиотеки, университеты и прочие образовательные учреждения также черпают силу из домена знаний.
Боги знания варьируются от повелителей магии до покровителей ремесла и изобретательства. В Фаэруне жрецы домена знаний поклоняются божествам учёности и изобретательности, таким как Огма, Гонд и многим другим.'::text, 'KNOWLEDGE_DOMAIN_FRHOF'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'KNOWLEDGE_DOMAIN_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'a6fce631-38fc-5e66-beab-dbe9b279019b'::uuid, 'Жрец. Домен знаний'::text, 'Раскрывайте секреты и хозяйничайте умом
Домен знаний ценит обучение и понимание превыше всего. Жрецы, обращающиеся к этому домену, изучают эзотерические знания, собирают старинные фолианты, исследуют тайные места и углубляются в процессы разума.
Боги знаний варьируются от мастеров магии до покровителей ремёсел и изобретений. Для них знания ценнее материального богатства, а желание учиться — это акт поклонения. Библиотеки, университеты и другие учреждения, посвящённые образованию, также черпают силу из домена знаний.
В Фаэруне жрецы домена знаний поклоняются богам учения и изобретательности, таким как Огма и Гонд. Другие могущественные божества (такие как Асмодей, Мистра, Саврас и Джергал) также включают жрецов домена знаний среди своих последователей, как и менее известные божества, такие как Денеир, Писарь Огмы, и Азут, слуга Мистры.'::text, 'CLERIC_KNOWLEDGE_DOMAIN_UAFRS'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_KNOWLEDGE_DOMAIN_UAFRS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '7199f17b-2d47-5044-97a6-a4528d03485e'::uuid, 'Жрец. Домен упокоения'::text, 'Воплощайте божественную силу смерти.
Домен упокоения сосредоточен на границе между жизнью и смертью. Для тех, кто черпает силу из этого домена, смерть — это основополагающая, естественная и неизбежная часть мультивселенной. Такие жрецы стремятся уничтожать нежить и проводить души в загробную жизнь (даже если сами души этого не хотят).
Магия этого домена также позволяет жрецам отсрочить смерть — особенно для тех, кому ещё предстоит совершить великие деяния в мире. Но это всего лишь отсрочка, а не отмена смерти, ведь могила всегда требует своего.'::text, 'CLERIC_GRAVE_DOMAIN_UAHS'::text, '4c3f4fdb-9b6f-4e33-88e5-775fea197e64'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'CLERIC_GRAVE_DOMAIN_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '88c9c12c-a80a-56fe-aa13-3a37a60613bc'::uuid, 'Изобретатель (EFA). Алхимик'::text, 'Создавайте магические элексиры и зелья
Алхимик — это эксперт в сочетании реагентов для создания магических эффектов. Алхимики используют свои творения, чтобы даровать или вытягивать жизнь.'::text, 'ARTIFICER_ALCHEMIST_UAA'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ARTIFICER_ALCHEMIST_UAA'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '7d8ec348-42bc-5040-8d76-39d539f1204f'::uuid, 'Изобретатель (EFA). Артиллерист'::text, 'Получите дальнобойную разрушительную мощь
Артиллерист специализируется на использовании магии для метания энергии, снарядов и взрывов на поле боя.'::text, 'ARTIFICER_ARTILLERIST_UAA'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ARTIFICER_ARTILLERIST_UAA'::text
