INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'f17af91c-a216-5af7-b970-01d550ee9e90'::uuid, 'Изобретатель (EFA). Боевой кузнец'::text, 'Командуйте конструктом-защитником
Боевой кузнец сочетает в себе роль защитника и медика, являясь экспертом по защите союзников и ремонту как снаряжения, так и живых существ. Чтобы помочь своей работе, боевых кузнецов сопровождает стальной защитник — защитный компаньон, созданный их собственными руками.'::text, 'ARTIFICER_BATTLE_SMITH_UAA'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ARTIFICER_BATTLE_SMITH_UAA'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '43856aad-3bf0-5805-8406-f16b15a22d09'::uuid, 'Изобретатель (EFA). Бронник'::text, 'Создавайте магическую броню для усиления своих умений
Изобретатель, который специализируется на создании доспехов, модифицирует их так, чтобы они действовали почти как вторая кожа. Эти доспехи усиливаются, чтобы улучшить магию изобретателя, мощно атаковать и формировать грозную защиту.'::text, 'ARTIFICER_ARMORER_UAA'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ARTIFICER_ARMORER_UAA'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '2ff8cdb4-6fd8-5615-9a6d-da4633b11fac'::uuid, 'Изобретатель (EFA). Картограф'::text, 'Прокладывайте выгодные маршруты сквозь хаос
Картографы — непревзойдённые навигаторы и разведчики. Используя свои изобретения, они могут выделять угрозы, защищать союзников и открывать порталы в дальние уголки.'::text, 'ARTIFICER_CARTOGRAPHER_UAEU'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
