INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '54c62e0c-1daf-58d5-9b43-93aa61bd135b'::uuid, 'Изобретатель (EFA). Реаниматор'::text, 'Собирайте трупы, чтобы воскрешать мёртвых
Реаниматоры бросают вызов законам природы ради жутких экспериментов. Эти мрачные изобретатели сшивают слуг из разрозненных тел, используют гнусную магию для усиления живых и превращают искусство некромантии в пугающую науку.'::text, 'ARTIFICER_REANIMATOR_UAHS'::text, 'dc23fb8a-a8d8-4e98-be5f-5cdba6391841'::uuid
WHERE NOT EXISTS (
