INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '3477f60e-7bee-5c35-b0da-2dcd49db933e'::uuid, 'Колдун. Покровитель Архифея'::text, 'Заключите сделку с капризной феей
Ваш договор опирается на силу Страны фей. Выбрав этот подкласс, вы заключаете договор с архифеей, например, с Морозным Принцем, Королевой Воздуха и тьмы — правительницей Сумеречного Двора, Титанией из Летнего двора или древней каргой. Или же вы можете прибегнуть к помощи целого спектра фей, сплетая паутину покровительств и одолжений. Кем бы они ни были, ваш покровитель часто бывает непостижимым и причудливым.'::text, 'WARLOCK_ARCHFEY_PATRON_PHB'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_ARCHFEY_PATRON_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '05d5bca7-eeba-5d83-ace0-61499e0b5a67'::uuid, 'Колдун. Покровитель Великий древний'::text, 'Познайте тайны непостижимых существ
Выбрав этот подкласс, вы можете связать себя с непостижимым существом из Дальнего предела или древним богом — таким, как Тариздун, Скованный Бог; Заргон, Возвращающий; Хадар, Тёмный Голод; или Великий Ктулху. Или вы можете воззвать к нескольким сущностям, не связывая себя с одной. Мотивы этих существ непостижимы, а Великий древний может быть безразличен к вашему существованию. Но секреты, которые вы узнали, всё же позволяют вам черпать из него чужеродную магию.'::text, 'WARLOCK_GREAT_OLD_ONE_PATRON_PHB'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_GREAT_OLD_ONE_PATRON_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b661068e-df9e-5c02-b004-388d2ab447ce'::uuid, 'Колдун. Покровитель Исчадие'::text, 'Заключите сделку с Нижними планами
В вашем договоре фигурируют Нижние планы — царства вечных мук. Вы можете заключить договор с повелителем демонов, таким как Демогоргон или Оркус, с архидьяволом, таким как Асмодей, или с особенно могущественным исчадием — балором, юголотом или ночной каргой. Цели таких покровителей злы: развращение или уничтожение всего сущего, в конечном счёте включая вас, и ваш путь определяется тем, насколько вы будете стремиться противостоять этим целям.'::text, 'WARLOCK_FIEND_PATRON_PHB'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_FIEND_PATRON_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '2d9f44ec-fc88-54ad-a7af-f6fbc6e3f6df'::uuid, 'Колдун. Покровитель Небожитель'::text, 'Используйте силу небес
Ваш договор опирается на Верхние планы — царства вечного блаженства. Вы можете заключить соглашение с эмпиреем, коатлем, сфинксом, единорогом или другой небесной сущностью. Или же вы можете обратиться к множеству подобных существ, чтобы достичь целей, совпадающих с их целями. Заключённый вами договор позволяет вам почувствовать толику священного света, озаряющего мультивселенную.'::text, 'WARLOCK_CELESTIAL_PATRON_PHB'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_CELESTIAL_PATRON_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '13d11859-6c81-58f7-9505-2c3b0a0f9d37'::uuid, 'Колдун. Покровитель Ведьмовской клинок'::text, 'Вы заключили договор с разумным магическим оружием и проклятыми силами, заключёнными в его клинке. Такое оружие может быть мечом, висящим у пояса колдуна, или же прославленным магическим артефактом, хранящимся в ином месте, но проецирующим свою силу сквозь мультивселенную ради реализации своих хитроумных замыслов. Тем, кто готов следовать прихотям этого оружия, эти загадочные покровители даруют силу насылать зловредные проклятия, наносить сокрушительные удары и усиливать носителя клинка.'::text, 'WARLOCK_HEXBLADE_PATRON_UAHS'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_HEXBLADE_PATRON_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '3a866b6c-46ff-575d-a4b5-520d22cb2cd0'::uuid, 'Колдун. Покровитель Король-чародей'::text, 'Воплощайте мощь тирании чудовищных правителей.
Ваш договор черпает силу от чудовищного тирана, подобного полубогу или невероятно могущественному заклинателю. Через свой договор вы становитесь вестником его интересов в мире, проводником его влияния и искажающей разум псионической силы.'::text, 'WARLOCK_SORCERER_KING_PATRON_UAAS'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_SORCERER_KING_PATRON_UAAS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '15e98953-a158-530f-b10f-303952266038'::uuid, 'Колдун. Покровитель Нежить'::text, 'Бросьте вызов смерти ради нечестивой силы
Вы заключили договор с существом, которое нарушает круговорот жизни и смерти: могущественным личем, вампиром или другим воплощением нежити. Когда-то бывшие смертными, эти древние покровители знают путь к власти и лазейки, ведущие за порог смерти. Они с готовностью делятся этим нечестивым знанием, а также другими тайнами, с теми, кто исполняет их волю среди живых.'::text, 'WARLOCK_UNDEAD_PATRON_UAHS'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARLOCK_UNDEAD_PATRON_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '48fc35c9-44f5-5805-9845-37daa23f0887'::uuid, 'Колдун. Покровитель-реликт'::text, 'Овладей остатками силы умирающего бога
Твой пакт черпает силу из умирающего бога — существа, некогда почитаемого бесчисленными последователями, но ныне забытого и покинутого. Этот умирающий бог, известный как реликт, мог быть благожелательным, злым или странным и непостижимым, однако теперь он одержим стремлением вернуть утраченное могущество. Реликту необходима твоя помощь, и взамен он готов поделиться с тобой остатками своей силы.'::text, 'VESTIGE_PATRON_UAMS'::text, '65b5e743-618e-4459-b92b-0643594435e4'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'VESTIGE_PATRON_UAMS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '1bd5f5af-889e-5e65-80a5-ecfa26037a65'::uuid, 'Монах. Мастер Милосердия'::text, 'Манипулируйте силами жизни и смерти.
Мастера Милосердия манипулируют жизненной силой других. Эти монахи — странствующие целители, но они также способны быстро оборвать жизни своих врагов. Они часто носят маски, представляя себя безликими носителями силы жизни и смерти.'::text, 'MONK_WARRIOR_OF_MERCY_PHB'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MONK_WARRIOR_OF_MERCY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b70d79c6-e74d-5642-8835-1c9b100a7c1d'::uuid, 'Монах. Мастер Открытой ладони'::text, 'Мастер техник безоружного боя.
Мастера Открытой ладони — эксперты безоружного боя. Они изучают техники, позволяющие толкать и сбивать с ног своих противников, а также манипулировать своей энергией для защиты от урона.'::text, 'MONK_WARRIOR_OF_THE_OPEN_HAND_PHB'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MONK_WARRIOR_OF_THE_OPEN_HAND_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '9ab52a6b-1bec-597a-8477-f3aff28fb271'::uuid, 'Монах. Мастер Стихий'::text, 'Используйте удары и всплески стихийной силы.
Мастера Стихий черпают силу из Элементальных планов. Используя свой сверхъестественный дух, эти монахи на мгновение укрощают энергию Элементального хаоса, чтобы усилить себя как в бою, так и вне его.'::text, 'MONK_WARRIOR_OF_THE_ELEMENTS_PHB'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MONK_WARRIOR_OF_THE_ELEMENTS_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'e856dd3c-673d-54eb-8b43-39d0824427fb'::uuid, 'Монах. Мастер Тени'::text, 'Используйте силу тени для скрытности и уловок.
Мастера Тени практикуют скрытность и уловки, используя силу царства Теней. Они чувствуют себя во тьме как дома, способны окутывать себя мраком для сокрытия, перемещаться из тени в тень и принимать призрачную форму.'::text, 'MONK_WARRIOR_OF_SHADOW_PHB'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MONK_WARRIOR_OF_SHADOW_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '8655f44d-9a1f-5ca9-9ac5-9d57e9b7af16'::uuid, 'Монах. Мастер мистических искусств'::text, 'Объединяй искусств боя и мистики
Мастера мистических искусств владеют магией, дополняя ею своё боевое мастерство. Они направляют сверхъестественную концентрацию, чтобы усиливать как магические, так и физические способности.'::text, 'WARRIOR_OF_THE_MYSTIC_ARTS_UAMS'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARRIOR_OF_THE_MYSTIC_ARTS_UAMS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '270e8770-e635-5780-b074-f4e17ddbb96c'::uuid, 'Монах. Мастер опьянения'::text, 'Пейте для сокрушения и обмана врагов.
Мастера опьянения двигаются резко и непредсказуемо, как и подобает опьяневшему. Эти монахи пошатываются на неустойчивых ногах, создавая видимость неумелости, чтобы затем оказаться крайне неудобными противниками. Их, казалось бы, случайные спотыкания скрывают тщательно выстроенный танец блоков, парирований, атак, выпадов и отступлений. 
Мастера опьянения часто любят прикидываться дураками, чтобы развеселить угнетённых или преподать урок смирения надменным. Однако в бою такие монахи — это безумные, но мастерски владеющие собой враги.'::text, 'WARRIOR_OF_INTOXICATION_UASU'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WARRIOR_OF_INTOXICATION_UASU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '5b388811-22e6-57db-b231-0437f393482f'::uuid, 'Монах. Мастер тату'::text, 'Улучшайте себя магическими татуировками
Черпая вдохновение из различных традиций нанесения узоров на тело, распространённых по всей Мультивселенной, татуированные воины умеют пользоваться силой магии, заключённой в их магических татуировках. По мере роста в воинском мастерстве и проникновения в суть мира эти монахи получают новые татуировки. Они могут изменять форму своих рисунков, открывая широкий набор физических и магических эффектов, чтобы одолеть врагов.'::text, 'MONK_TATTOOED_WARRIOR_UAAU'::text, 'b0a7f658-f59c-4199-9953-511edd83e822'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MONK_TATTOOED_WARRIOR_UAAU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'bdf98ea7-c279-5265-8863-a37fcdf08679'::uuid, 'Паладин. Клятва Древних'::text, 'Сохраняйте жизнь и свет в мире.
Клятва Древних так же стара, как первые эльфы. Паладины, принявшие эту клятву, почитают свет; они любят прекрасные и дарующие жизнь вещи больше, чем какие-либо принципы чести, мужества и справедливости. Они часто украшают свои доспехи и одежду изображениями природы — листьев, рогов или цветов — чтобы отразить свою приверженность к сохранению жизни и света.
Паладины Древних следуют этим заповедям:
- Разжигайте свет надежды.
- Защищайте жизнь.
- Восторгайтесь искусством и смехом.'::text, 'PALADIN_OATH_OF_THE_ANCIENTS_PHB'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PALADIN_OATH_OF_THE_ANCIENTS_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '18425d74-729e-5e3d-b5a1-74a413219d65'::uuid, 'Паладин. Клятва Мести'::text, 'Наказывайте злодеев любой ценой
Клятва мести — это торжественное обязательство наказать тех, кто совершил тяжкие злодеяния. Когда армии истребляют беззащитных деревенских жителей, когда тиран пренебрегает волей богов, когда гильдия воров становится слишком жестокой, когда дракон разоряет окрестности — в такие времена появляются паладины, которые приносят Клятва мести, чтобы установить, что правильно, а что ошибочно.
Паладины Мести следуют этим заповедям:
- Никакой пощады злу.
- Боритесь с несправедливостью и её причинами.
- Помогайте пострадавшим от несправедливости.'::text, 'PALADIN_OATH_OF_VENGEANCE_PHB'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PALADIN_OATH_OF_VENGEANCE_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'ef3ed3f1-b697-5fb8-b712-df8b6cecf806'::uuid, 'Паладин. Клятва Преданности'::text, 'Поддерживайте идеалы справедливости и порядка.
Клятва Преданности связывает паладинов с идеалами справедливости и порядка. Эти паладины воплощают идеал рыцаря в сияющих доспехах. Они придерживаются высочайших стандартов поведения и некоторые (к лучшему или худшему) предъявляют те же требования к остальному миру.
Многие из тех, кто приносит эту клятву, преданы богам закона и добра и используют заповеди своих богов как мерило личной преданности. Другие почитают ангелов как свои идеалы и встраивают образы ангельских крыльев в свои шлемы или гербы.
Паладины Преданности следуют этим заповедям:
- Пусть ваши слова будут вашими обещаниями.
- Защищайте слабых и не бойтесь действовать.
- Пусть ваши благородные поступки будут примером.'::text, 'PALADIN_OATH_OF_DEVOTION_PHB'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PALADIN_OATH_OF_DEVOTION_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '05c413fa-2025-5123-8f32-d4db2544189a'::uuid, 'Паладин. Клятва Славы'::text, 'Стремитесь к вершинам героизма.
Паладины, принявшие Клятву Славы, верят, что они и их спутники предназначены достичь славы через героические поступки. Они усердно тренируются и вдохновляют своих соратников, чтобы все были готовы, когда судьба позовёт.
Паладины Славы следуют этим заповедям:
- Старайтесь быть известны своими деяниями.
- Встречайте трудности с мужеством.
- Вдохновляйте других стремиться к славе.'::text, 'PALADIN_OATH_OF_GLORY_PHB'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PALADIN_OATH_OF_GLORY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '84d0516d-bfec-5212-a51e-9b501f5b127e'::uuid, 'Паладин. Клятва благородных гениев '::text, 'Являйте стихии гениев в великолепии.
Паладины, принесшие клятву благородных гениев, почитают силы стихийных планов. Через эту клятву они черпают могущество у четырёх видов гениев: дао, повелителей земли; джиннов, владык воздуха; ифритов, хозяев огня; и маридов, властителей воды. Во Фаэруне многие паладины, дающие эту клятву, родом из Калимшана — земли, наполненной гениями.
Такие паладины часто странствуют по всем Королевствам и даже за их пределы — включая стихийные планы.
- Сейте семена созидания среди пепла разрушения.
- Ведите за собой с великолепием и грацией.
- Почитайте стихии — и страшитесь их гнева.'::text, 'PALADIN_OATH_OF_THE_NOBLE_GENIES_FRHOF'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PALADIN_OATH_OF_THE_NOBLE_GENIES_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '32253b5d-4cd5-5fba-aafe-7e0a99ba1cda'::uuid, 'Паладин. Клятва благородных гениев'::text, 'Являйте стихии гениев в великолепии
Паладины, принесшие клятву благородных гениев, почитают силы стихийных планов. Приняв эту клятву, паладины черпают силу из четырёх типов гениев: дао, повелителей земли; джиннов, повелителей воздуха; ифритов, повелителей огня; и маридов, повелителей воды, чтобы создавать великолепные и разрушительные проявления стихийной мощи.
На Фаэруне многие паладины, приносящие эту клятву, происходят из Калимшана — края, насыщенного джиннами. Несмотря на свои крепкие местные корни, эти калишитские паладины часто отправляются на задания, которые ведут их по всем Забытым королевствам и даже за его пределы, включая, естественно, Стихийные планы.
- Создавай, разрушая.
- Веди за собой с великолепием и грацией.
- Уважай стихии и бойся их гнева.'::text, 'OATH_OF_THE_NOBLE_GENIES_UAFRS'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'OATH_OF_THE_NOBLE_GENIES_UAFRS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '23860f08-5f16-5cb3-970e-4895843d1ad8'::uuid, 'Паладин. Клятва чаростража'::text, 'Защищай союзников от злодейской магии.
Паладины, приносящие Клятву Чаростражей, дают обет сражаться с теми, кто использует магию во вред другим. Зачастую они служат телохранителями достойных магов, но их важнейшая роль — защита союзников от разрушительных магических атак. Те, кто приносит эту клятву, следят за тем, чтобы злодеи, злоупотребляющие магией, были преданы правосудию.
- Защищай невинных от порочных магов.
- Не допускай попадания магии в руки злодеев.
- Оберегай магов, которые используют магию честно и ответственно.'::text, 'OATH_OF_THE_SPELLGUARD_UAMS'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'OATH_OF_THE_SPELLGUARD_UAMS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '9ffe86d9-676c-5605-ab47-1c7c12ed0d73'::uuid, 'Паладин. Клятвопреступник'::text, 'Обретайте великую силу любой ценой.
Сила обета паладина столь велика, что даже в извращённой форме она сохраняет могущество, когда обет нарушается. 
Когда паладин предаёт заветы своего обета из-за порчи, гордыни или жажды власти, он теряет благословение, дарованное изначальным обетом, но иногда обретает зловещее благословение клятвопреступника вместо него. Клятвопреступники используют страх и сокрушительную силу для достижения своих целей. 
Хотя многие из них окончательно теряют возможность искупления, некоторые паладины принимают этот обет, чтобы совершить великое и благородное деяние для искупления своих прошлых грехов.
На усмотрение Мастера, паладин любого уровня, нарушивший заветы своего обета, может утратить эффекты своего изначального подкласса и вместо этого получить умения подкласса клятвопреступник. Альтернативно, паладин может выбрать этот подкласс на 3 уровне, если предыстория персонажа включает падение с пути добродетели.
Эти паладины часто следуют следующим заветам:
- Страх — это инструмент в руках сильных.
- Стремись к силе любой ценой.
- Делай то, что должно быть сделано, но никогда не теряй из виду свою цель.'::text, 'OATHBREAKER_UASU'::text, 'fbe7a3ee-c355-4ec0-95f0-73c999107e5e'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'OATHBREAKER_UASU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '9bdbb65d-4f41-57af-9eb5-3eb59ff2a620'::uuid, 'Плут. Вор'::text, 'Охотьтесь за сокровищами, как заправский приключенец.
Ваше ремесло можно описать как смесь деятельности взломщика, исследователя и охотника за сокровищами. Иначе говоря, вы — эталонный приключенец.
Помимо улучшения ловкости и скрытности, вы приобретаете навыки, которые пригодятся во время изучения руин, а также извлечения максимальной выгоды из найденных в них магических предметов.'::text, 'ROGUE_THIEF_PHB'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_THIEF_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '35c196a5-b125-5add-a870-202c2f0afa5e'::uuid, 'Плут. Клинок души'::text, 'Разите врагов псионическими клинками.
Клинок души поражает врагов силой разума, пронзая как физические, так и психические барьеры.
Эти плуты обнаруживают в себе псионическую силу и направляют её в интересах своей плутовской деятельности.
Ваши псионические способности Клинка души, возможно, проявлялись с детства, раскрывая весь свой потенциал только во время стресса в приключениях. А возможно, вы разыскали орден адептов-экстрасенсов и потратили годы на изучение способов проявления этой силы.'::text, 'ROGUE_SOULKNIFE_PHB'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_SOULKNIFE_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '8d84aa1e-f4c1-59dc-847b-5a18f0493676'::uuid, 'Плут. Мистический ловкач'::text, 'Усильте скрытность с помощью заклинаний.
Некоторые плуты усиливают свои прекрасно отточенные навыки скрытности и ловкости магией, делая магические приёмы подспорьем для своего ремесла.
Одни Мистические ловкачи используют свои таланты для воровства и грабежа, другие же — потехи ради.'::text, 'ROGUE_ARCANE_TRICKSTER_PHB'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_ARCANE_TRICKSTER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '28aa8921-9d20-57be-a088-2295d906675f'::uuid, 'Плут. Убийца'::text, 'Упражняйтесь в мрачном искусстве смерти.
Обучение убийцы сосредоточено на использовании скрытности, яда и маскировки, чтобы устранять врагов со смертельной эффективностью. Хотя некоторые плуты, избравшие этот путь, являются наёмными убийцами, шпионами или охотниками за головами, возможности этого подкласса одинаково полезны для приключенцев, сталкивающихся с различными чудовищными врагами.'::text, 'ROGUE_ASSASSIN_PHB'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_ASSASSIN_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '75a74a53-1247-530d-a6a4-656250ad0289'::uuid, 'Плут. Наследник троих'::text, 'Станьте жутким агентом зла
Наследник троих черпает силу у группы злобных богов, известных как Трое мёртвых: Бэйн, божество тирании; Баал, божество насилия и убийства; Миркул, божество смерти.
Некоторые плуты этого подкласса посвящают себя этим трём мрачным богам, а другие вынуждены идти по этому пути из-за проклятия. Так или иначе, сила наследника проявляется в виде различных оккультных даров, а также в пугающем мастерстве наносить удары и вселять ужас в врагов.
Наследники троих чаще всего встречаются во Вратах Балдура, где Трое мёртвых долгое время боролись за влияние над сердцами смертных. Подземные культы Бэйна, Баала и Миркула часто считают наследников троих своими наиболее полезными агентами. За пределами Врат Балдура светские воровские гильдии, такие как Тени Амна или гильдия Занатара в Глубоководье, могут с осторожностью нанимать наследников троих для выполнения особенно жестоких контрактов.'::text, 'ROGUE_SCION_OF_THE_THREE_FRHOF'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_SCION_OF_THE_THREE_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'b3711163-fcc0-5e60-8bce-00725e9b617a'::uuid, 'Плут. Наследник троих'::text, 'Станьте жутким агентом зла
Наследник троих черпает силу у группы злобных богов, известных как Трое мёртвых: Бэйн, божество тирании; Баал, божество насилия и убийства; Миркул, божество смерти.
Некоторые плуты этого подкласса посвящают себя этим трём мрачным богам, а другие вынуждены идти по этому пути из-за проклятия. Так или иначе, сила наследника проявляется в виде различных оккультных даров, а также в пугающем мастерстве наносить удары и вселять ужас в врагов.
Наследники троих чаще всего встречаются во Вратах Балдура, где Трое мёртвых долгое время боролись за влияние над сердцами смертных. Подземные культы Бэйна, Баала и Миркула часто считают наследников троих своими наиболее полезными агентами. За пределами Врат Балдура светские воровские гильдии, такие как Тени Амна или гильдия Занатара в Глубоководье, могут с осторожностью нанимать наследников троих для выполнения особенно жестоких контрактов.'::text, 'ROGUE_SCION_OF_THE_THREE_UAFRS'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_SCION_OF_THE_THREE_UAFRS'::text
