INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '1dfe9eaf-26ba-51c9-9f2a-3e5ccab7158a'::uuid, 'Плут. Похититель магии'::text, 'Похищай магическую силу, чтобы усилить себя.
Пока обычные воры режут кошельки и грабят дома, Похититель магии охотится за куда более ценным трофеем — магией.
Похититель магии выслеживает заклинателей, перенаправляя их магическую силу и уклоняясь от заклинаний школы прорицания, чтобы завладеть магической мощью острием своего клинка.'::text, 'MAGIC_STEALER_UAMS'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'MAGIC_STEALER_UAMS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'c8b25d9a-2a3b-526b-aee7-137502a439bb'::uuid, 'Плут. Фантом'::text, 'Примите смерть и обретите призрачную силу
Некоторые плуты идут по грани между жизнью и смертью, отправляя противников в могилу и скользя по миру незаметно, словно духи.
В этом стремлении плут может обрести мистическую связь со смертью. Такой персонаж погружается в негативную энергию, наполняет свои удары смертоносной силой и крадёт знания у ушедших душ.
Воровские гильдии высоко ценят таких плутов как мастеров сбора информации и шпионажа.'::text, 'ROGUE_PHANTOM_UAHS'::text, '066b7e5d-85a9-4a53-b485-a09da72ba2e0'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'ROGUE_PHANTOM_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '89b1deff-0ac7-508d-8379-b46b11076a46'::uuid, 'Псионик (UAPU). Метаморф'::text, 'Формируйте жизнь и плоть силой разума.
Ваша власть над псионическими силами направлена внутрь. Ваша собственная плоть становится для вас подобна глине, и вы формируете её, превращая в идеальный сосуд для своих псионических сил. Опыт в манипулировании жизненной энергией также позволяет вам изменять жизненную силу как союзников, так и врагов.'::text, 'PSION_METAMORPH_UAPU'::text, '4c8d06b4-4a60-4dc4-8b0e-94a2e8fb8f01'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PSION_METAMORPH_UAPU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '647f96d6-6c1b-5dc3-be50-b1fb64d6129d'::uuid, 'Псионик (UAPU). Психокинетик'::text, ''::text, 'PSION_PSYKINETIC_UAPU'::text, '4c8d06b4-4a60-4dc4-8b0e-94a2e8fb8f01'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PSION_PSYKINETIC_UAPU'::text
