INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '9c93eb16-732f-54b0-81f3-4a0c2811338c'::uuid, 'Псионик (UAPU). Телепат'::text, 'Проявляйте тактику в ландшафте разума
Телепаты — мастера ментальной магии. Они используют свои псионические силы во всех вопросах разума — будь то укрепление ментальной защиты союзников или скрытое проникновение в мысли других. Телепат может быть как оплотом псионической помощи, так и хитрым манипулятором.'::text, 'PSION_TELEPATH_UAPU'::text, '4c8d06b4-4a60-4dc4-8b0e-94a2e8fb8f01'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'PSION_TELEPATH_UAPU'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '4ba66846-746a-50d3-a593-5487d7f4d5f0'::uuid, 'Следопыт. Охотник'::text, 'Оберегайте людей и природу от разрушения.
Вы преследуете добычу на любой местности, используя свои способности Охотника, чтобы защитить природу и людей от сил, которые стремятся их уничтожить.'::text, 'RANGER_HUNTER_PHB'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_HUNTER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '31d32113-df4c-525b-b293-4c1df120020a'::uuid, 'Следопыт. Повелитель зверей'::text, 'Свяжите себя с первобытным зверем.
Используя первобытную магию и глубокую связь с миром природы, Повелитель зверей устанавливает мистические узы с особым животным.'::text, 'RANGER_BEAST_MASTER_PHB'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_BEAST_MASTER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '44f9bed8-14cd-5317-940a-878e4a9b2ec7'::uuid, 'Следопыт. Сумрачный охотник'::text, 'Используйте магию теней в борьбе с врагами.
Сумрачные охотники ощущают себя как дома даже в самых тёмных местах. Они орудуют магией Царство теней, направляя её против врагов, что рыщут во мраке.'::text, 'RANGER_GLOOM_STALKER_PHB'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_GLOOM_STALKER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '4c6dd695-d862-5c20-abf8-83dd8efbe936'::uuid, 'Следопыт. Фейский странник'::text, 'Сражайтесь с весельем и яростью фей.
Благодаря дару архифеи или преобразившему вас месту в Стране фей, вас окружает фейская таинственность.
Как бы вы ни обрели свою фейскую магию, теперь вы — Фейский странник. Ваш радостный смех осветляет сердца угнетённых, а ваше воинское мастерство наводит ужас на врагов, ибо веселье фей велико, а их ярость — ужасна.'::text, 'RANGER_FEY_WANDERER_PHB'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_FEY_WANDERER_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'd56aa3fe-1359-56b2-be8e-9c0006b5805b'::uuid, 'Следопыт. Зимний странник'::text, 'Переживите ужасы ледяных пустошей
Зимние странники оттачивают своё мастерство в суровых и замёрзших диких землях, таких как Долина ледяного ветра. Покрытые инеем, эти беспощадные следопыты охотятся на чудовищ арктических пустошей, со временем сами превращаясь в ледяные ужасы.
Более других следопытов Долины ледяного ветра, зимние странники известны своим глубоким знанием паранормальных явлений, характерных для этих мест, включая скрытую магию павших городов Нетерила, эндемичных монстров, таких как йети и скальные кошки, а также растущую угрозу вторжений из Подземья.
Благодаря своему холодному прагматизму, пугающей магии и безупречному знанию региона, эти зимние странники вызывают одновременно уважение и страх.
Жители Десяти городов говорят, что частое столкновение зимних странников со злыми сущностями даёт им их устрашающие силы, в то время как многие регхедские кочевники верят, что духи природы наделяют зимних странников уникальным проклятием.'::text, 'RANGER_WINTER_WALKER_FRHOF'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_WINTER_WALKER_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '227f9e94-101e-55d1-a413-cdb2d47f6306'::uuid, 'Следопыт. Зимний странник'::text, 'Переживите ужасы ледяных пустошей.
Зимние странники оттачивают своё мастерство в суровых и замёрзших диких землях, таких как Долина ледяного ветра. Покрытые инеем, эти беспощадные следопыты охотятся на монстров арктических пустошей, со временем сами превращаясь в ледяные ужасы.
Более других следопытов Долины ледяного ветра, зимние странники известны своим глубоким знанием паранормальных явлений, характерных для этих мест, включая скрытую магию павших городов Нетерила, эндемичных монстров, таких как йети и скальные кошки, а также растущую угрозу вторжений из Подземья.
В обмен на свою холодную прагматику, пугающую магию и знание региона, эти зимние странники вызывают одновременно уважение и страх.
Жители Десяти городов говорят, что частое столкновение зимних странников со злыми сущностями даёт им их устрашающие силы, в то время как многие регхедские кочевники верят, что духи природы наделяют зимних странников уникальным проклятием.'::text, 'RANGER_WINTER_WALKER_UAFRS'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_WINTER_WALKER_UAFRS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '04e2d69f-5c10-58ce-9c25-6ed383385fc1'::uuid, 'Следопыт. Страж пустоты'::text, 'Черпайте силу у древних ужасов дикого мира
Легенды гласят, что самые древние и пугающие ужасы таятся глубоко в старых землях — непостижимые и кровожадные сущности из бесплодной почвы и острых когтей. Стражи пустоты почитают этих существ и черпают силу у них, превращаясь в таких же беспощадных и чудовищных хранителей, что бродят по неровным побережьям, крутым горным утёсам и другим тёмным местам.'::text, 'RANGER_HOLLOW_WARDEN_UAHS'::text, 'eeb72220-6167-48b9-9f58-75049335ee35'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'RANGER_HOLLOW_WARDEN_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '96877aca-6e73-5649-a8af-2764b66192ef'::uuid, 'Дикое чародейство'::text, 'Высвободите хаотическую магию
Ваша внутренняя магия проистекает от диких сил хаоса, лежащих в основе мироздания. Вы, или ваш предок, возможно, подверглись воздействию сырой магии, например, через межпланарный портал, ведущий в Лимбо или Стихийные планы. Быть может, вы были благословлены феей или отмечены демоном. Или ваша магия может быть случайностью вашего рождения, без какой-либо причины. Вне зависимости от её происхождения, хаотическая магия бурлит внутри вас, готовая вырваться наружу.'::text, 'WILD_MAGIC_SORCERY_PHB'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'WILD_MAGIC_SORCERY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '8b70408c-1d40-5176-acd7-6ba51645b4d7'::uuid, 'Драконье чародейство'::text, 'Дышите магией драконов
Ваша врождённая магия берёт своё начало от дара драконов. Возможно, древний дракон, столкнувшийся со смертью, завещал часть своей магической силы вам или вашему предку. Быть может, вы впитали магию из места, наполненного силой драконов. Или вы держали в руках нечто ценное из сокровищницы дракона, что было пропитано его силой. А может, ваш предок и есть дракон.'::text, 'SORCERER_DRACONIC_SORCERY_PHB'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_DRACONIC_SORCERY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'd86128ac-43db-5ff7-9a55-60de5a794096'::uuid, 'Искажённое чародейство'::text, 'Овладейте неестественной псионической силой
Чужеродное влияние оплело своими щупальцами ваш разум, даруя вам псионическую силу. Теперь вы можете касаться разумов других существ с помощью этой силы и изменять мир вокруг себя. Будет ли эта сила сиять в вас, как маяк надежды для других? Или вы станете источником ужаса для тех, кто почувствует укол вашего разума?
Возможно, психические ветра из Астрального плана принесли вам псионическую энергию, или вы подверглись воздействию искажённого влияния Дальнего предела. Альтернативно — вам имплантировали головастика свежевателя разума, но ваша трансформация в иллитида так и не произошла; теперь псионические силы головастика — ваши. Как бы вы ни приобрели эту силу, ваш разум пылает ею.'::text, 'SORCERER_ABERRANT_SORCERY_PHB'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_ABERRANT_SORCERY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '0cbd666d-1e4f-5b4e-b784-6c1ff0275a6e'::uuid, 'Чародейство порядка'::text, 'Направляйте космические силы порядка
Космическая сила порядка наполнила вас магией. Эта сила проистекает из Механуса или подобного ему плана — царства существования, сформированного исключительно соображениями эффективности, как у часового механизма. Вы или кто-то из вашего рода могли быть вовлечены в махинации модронов — существ порядка, населяющих Механус. Возможно, кто-то из ваших предков даже принимал участие в Великом марше модронов. Каким бы ни был источник мощи внутри вас, сила порядка может показаться странной другим, но для вас она — часть огромной и славной системы.'::text, 'SORCERER_CLOCKWORK_SORCERY_PHB'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_CLOCKWORK_SORCERY_PHB'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'c6257bba-2a91-54a5-81be-d27c1d87e5e3'::uuid, 'Чародейство чаропламени'::text, 'Излучайте сырой магический потенциал
Ваше врождённое могущество проистекает из самого источника магии — Плетения. Эта связь проявляется в виде редкой способности, известной как чаропламя [spellfire], и вы пылаете всплесками этой первозданной магии. Ваш талант управлять чаропламенем позволяет вам исцелять союзников, сжигать врагов и поглощать мощные заклинания.
Обладатели чаропламени, как правило, являются любопытными странниками и искателями приключений. Многие из них путешествуют между космополитичными поселениями, такими как города вдоль Побережья Мечей, используя свою магию во благо общего дела.
Другие стремятся раскрыть свои необычные способности, исследуя не менее загадочные земли — от магически опустошённых пустошей пустыни Анарох до одухотворённых богами земель Старых Империй.
Где бы они ни оказались в Забытых королевствах, чародеи чаропламени нередко привлекают внимание фракций, интересующихся искусством арканы, таких как Арфисты и Культ Дракона.'::text, 'SORCERER_SPELLFIRE_SORCERY_FRHOF'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_SPELLFIRE_SORCERY_FRHOF'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '31d27b8a-5df7-5cd3-ae88-fa615707865b'::uuid, 'Осквернённое чародейство'::text, '[Высасывание жизни для катастрофических заклинаний
Ваша врождённая сила высасывает жизненную эссенцию из окружающего мира. По вашему велению существа заболевают, а растения превращаются в сухие оболочки. Вы черпаете силу из самой порчи жизни, истощая жизненные силы, чтобы подпитывать разрушительную магию.'::text, 'SORCERER_DEFILED_SORCERY_UAAS'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_DEFILED_SORCERY_UAAS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT '2a3a5834-5ff8-5105-ba55-401cb8b4f627'::uuid, 'Теневое чародейство'::text, 'Подчиняйте тьму и погибель своей воле
Ваша врождённая магия происходит из самого Царства теней. Возможно, вы происходите от существа из этого плана, или же когда-то подвергся воздействию зловещей энергии Царства теней, и она изменила тебя. Твое теневое чародейство позволяет тебе с лёгкостью повелевать тьмой, нежитью и страданиями.'::text, 'SORCERER_SHADOW_SORCERY_UAHS'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_SHADOW_SORCERY_UAHS'::text
);

INSERT INTO rules.default_2024_clazz (id, name, description, code, clazz_stats_id)
SELECT 'c580178d-dfe1-5da0-8633-b88587e61d05'::uuid, 'Чародейство чаропламени'::text, 'Излучайте сырой магический потенциал
Ваше врождённое могущество проистекает из самого источника магии: Плетения. Эта связь проявляется в виде редкой способности, известной как чаропламя, и вы пылаете всплесками этой сырой магии. Ваш талант управлять чаропламенем позволяет вам исцелять союзников, жечь врагов и поглощать мощные заклинания.
Обладатели чаропламени, как правило, являются любопытными приключенцами, склонными к странствиям. Многие из них путешествуют между космополитичными поселениями, такими как города вдоль Побережья мечей, и используют свою магию во благо общего дела.
Другие ставят приоритетом раскрытие собственных необычных способностей, исследуя столь же странные земли, начиная от магически опустошённых пустошей пустыни Анарох до одухотворённых богами земель Старых империй.
Где бы они ни оказались в Забытых королевствах, чародеи волшебного огня часто привлекают внимание фракций, интересующихся искусством арканы, таких как Арфисты и Культ дракона.'::text, 'SORCERER_SPELLFIRE_SORCERY_UAFRS'::text, '4f11a60a-b7c2-4892-a256-c26c1e9b2c12'::uuid
WHERE NOT EXISTS (
    SELECT 1 FROM rules.default_2024_clazz WHERE code = 'SORCERER_SPELLFIRE_SORCERY_UAFRS'::text
);
